def affine_encrypt(text, a, b):
    if gcd(a, 26) != 1:
        raise ValueError(" 'a' must be coprime to 26")
    
    result = ""
    for char in text.upper():
        if char.isalpha():
            x = ord(char) - ord('A')
            cipher_char = chr(((a * x + b) % 26) + ord('A'))
            result += cipher_char
    return result

